@pytest.mark.asyncio
async def test_batch_crawl_basic() -> None:
    """Batch crawl of 2 seed URLs with links to discover."""
    engine_config = CrawlConfig(max_depth=1, respect_robots_txt=False)
    engine = create_engine(engine_config)
    urls_base = os.environ.get(
        "MOCK_SERVER_BATCH_CRAWL_BASIC",
        os.environ["MOCK_SERVER_URL"] + "/fixtures/batch_crawl_basic",
    )
    urls = [
        p if p.startswith("http") else f"{urls_base}{p}" for p in ["/seed1", "/seed2"]
    ]

    result = await batch_crawl(engine, urls)
    assert result.completed_count == 2  # noqa: S101
    assert result.failed_count == 0  # noqa: S101
    assert result.total_count == 2  # noqa: S101


